async def _delete_label(hass: HomeAssistant, identifier: str) -> dict[str, Any]:
    reg = lr.async_get(hass)
    x = reg.async_get_label(identifier) or next(
        (y for y in reg.async_list_labels() if y.name == identifier), None)
